import{_ as e,o as r,c as a,a0 as l}from"./chunks/framework.Dx25mwie.js";const _=JSON.parse('{"title":"4步驟簡易長棍麵包 — 新手友善版","description":"Milk vs. Bread 的新手友善長棍配方，酵母多、水量高、操作簡單，適合第一次做長棍麵包。","frontmatter":{"title":"4步驟簡易長棍麵包 — 新手友善版","description":"Milk vs. Bread 的新手友善長棍配方，酵母多、水量高、操作簡單，適合第一次做長棍麵包。"},"headers":[],"relativePath":"docs/西式/4步驟簡易長棍麵包.md","filePath":"docs/西式/4步驟簡易長棍麵包.md"}'),n={name:"docs/西式/4步驟簡易長棍麵包.md"};function o(d,t,i,s,g,h){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="_4步驟簡易長棍麵包-—-新手友善版" tabindex="-1">4步驟簡易長棍麵包 — 新手友善版 <a class="header-anchor" href="#_4步驟簡易長棍麵包-—-新手友善版" aria-label="Permalink to &quot;4步驟簡易長棍麵包 — 新手友善版&quot;">​</a></h1><p><strong>來源：</strong> <a href="https://youtu.be/3TLAg6JsA88" target="_blank" rel="noreferrer">YouTube - Milk vs. Bread</a><strong>分享日期：</strong> 2026/06/08</p><hr><blockquote><p>相較於專業版（Fabrice主廚），這個配方更簡單、酵母用量更多、操作更快，適合新手入門！</p></blockquote><hr><h2 id="📝-配方-可做-2-條" tabindex="-1">📝 配方（可做 2 條） <a class="header-anchor" href="#📝-配方-可做-2-條" aria-label="Permalink to &quot;📝 配方（可做 2 條）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>材料</th><th>用量</th></tr></thead><tbody><tr><td>🌾 高筋麵粉（bread flour）</td><td><strong>500 g</strong></td></tr><tr><td>💧 水</td><td><strong>380 ml</strong></td></tr><tr><td>🧫 新鮮酵母</td><td><strong>10 g</strong></td></tr><tr><td>🧂 鹽</td><td><strong>10 g</strong></td></tr></tbody></table><hr><h2 id="👨‍🍳-4-大步驟" tabindex="-1">👨‍🍳 4 大步驟 <a class="header-anchor" href="#👨‍🍳-4-大步驟" aria-label="Permalink to &quot;👨‍🍳 4 大步驟&quot;">​</a></h2><h3 id="_1️⃣-攪拌" tabindex="-1">1️⃣ 攪拌 <a class="header-anchor" href="#_1️⃣-攪拌" aria-label="Permalink to &quot;1️⃣ 攪拌&quot;">​</a></h3><ul><li>水 380ml + 鮮酵母 10g → 用攪拌器拌勻</li><li>加入麵粉 500g + 鹽 10g → 攪拌均勻至無乾粉</li><li>⏱ <strong>靜置 30 分鐘</strong>（麵團會逐漸變得光滑有彈性）</li></ul><h3 id="_2️⃣-折疊與基礎發酵" tabindex="-1">2️⃣ 折疊與基礎發酵 <a class="header-anchor" href="#_2️⃣-折疊與基礎發酵" aria-label="Permalink to &quot;2️⃣ 折疊與基礎發酵&quot;">​</a></h3><ul><li>將麵團邊緣往中心<strong>折疊</strong></li><li>提起麵團<strong>輕拍</strong>排氣</li><li>保鮮膜蓋住</li><li>🌡️ <strong>溫暖處發酵至兩倍大</strong></li><li>或 <strong>冷藏 12 小時</strong>更方便</li></ul><h3 id="_3️⃣-整形" tabindex="-1">3️⃣ 整形 <a class="header-anchor" href="#_3️⃣-整形" aria-label="Permalink to &quot;3️⃣ 整形&quot;">​</a></h3><ul><li>桌面撒手粉</li><li>麵團分成 <strong>2 等份</strong></li><li>照影片方式折疊整形</li><li>⏱ <strong>靜置 20 分鐘</strong></li><li>用手掌輕拍，整形為長棍形狀</li><li>🌡️ <strong>溫暖處發酵至 1.5 倍大</strong></li></ul><h3 id="_4️⃣-烤焙" tabindex="-1">4️⃣ 烤焙 <a class="header-anchor" href="#_4️⃣-烤焙" aria-label="Permalink to &quot;4️⃣ 烤焙&quot;">​</a></h3><ul><li>表面撒乾粉</li><li><strong>斜切</strong>（約 <strong>45 度角</strong>），不要垂直切</li><li>烤箱預熱 <strong>235°C</strong></li><li>放入麵團後加<strong>熱水</strong>在底盤製造蒸氣</li><li>🔥 <strong>烤 25 分鐘</strong></li></ul><hr><h2 id="⚖️-兩種長棍食譜比一比" tabindex="-1">⚖️ 兩種長棍食譜比一比 <a class="header-anchor" href="#⚖️-兩種長棍食譜比一比" aria-label="Permalink to &quot;⚖️ 兩種長棍食譜比一比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th style="text-align:center;">專業版（Fabrice）</th><th style="text-align:center;">簡單版（Milk vs. Bread）</th></tr></thead><tbody><tr><td>🧫 酵母量</td><td style="text-align:center;">4g 鮮酵母</td><td style="text-align:center;"><strong>10g 鮮酵母</strong> 🏃</td></tr><tr><td>💧 水量</td><td style="text-align:center;">330g</td><td style="text-align:center;"><strong>380g</strong> 🫧</td></tr><tr><td>⏱ 前置</td><td style="text-align:center;">自解法45分</td><td style="text-align:center;">直接靜置30分</td></tr><tr><td>🧊 冷藏發酵</td><td style="text-align:center;">12小時</td><td style="text-align:center;">12小時（可選）</td></tr><tr><td>🌡️ 烤溫</td><td style="text-align:center;">250°C</td><td style="text-align:center;"><strong>235°C</strong></td></tr><tr><td>⏲️ 烤時</td><td style="text-align:center;">18~19分</td><td style="text-align:center;"><strong>25分</strong></td></tr><tr><td>🎯 難度</td><td style="text-align:center;">中高級</td><td style="text-align:center;"><strong>新手友善</strong> ✅</td></tr></tbody></table><hr><p><em>由 Hermes 於 2026/06/08 整理</em></p>',22)])])}const u=e(n,[["render",o]]);export{_ as __pageData,u as default};
